// Get the incoming message
const body = $input.first().json.body;
const userMessage = body.chatInput || body.message || '';

// Generate or get session ID
const sessionId = body.sessionId || `SESS_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

// Track negotiation state (stored in session)
const negotiationState = body.negotiationState || {
  stage: 'none', // none, collecting, negotiating, confirming
  orderData: {},
  negotiationCount: 0,
  bestPrice: null
};

return [{
  json: {
    userMessage: userMessage,
    sessionId: sessionId,
    timestamp: new Date().toISOString(),
    negotiationState: negotiationState
  }
}];

// Get AI response
const aiResponse = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';

// Extract intent and data
let intent = 'general';
let status = 'pending';
let orderData = {};
let cleanedResponse = aiResponse;
let discountOffered = null;
let newPrice = null;

// Check for ORDER_CONFIRMED
if (aiResponse.includes('ORDER_CONFIRMED')) {
  intent = 'order';
  status = 'confirmed';

  // Extract order details
  const productMatch = aiResponse.match(/Product: ([^|]+)/);
  const quantityMatch = aiResponse.match(/Quantity: ([^|]+)/);
  const nameMatch = aiResponse.match(/Name: ([^|]+)/);
  const phoneMatch = aiResponse.match(/Phone: ([^|]+)/);
  const addressMatch = aiResponse.match(/Address: ([^|]+)/);
  const totalMatch = aiResponse.match(/Total: \$?([^|]+)/);

  orderData = {
    product: productMatch ? productMatch[1].trim() : '',
    quantity: quantityMatch ? quantityMatch[1].trim() : '',
    name: nameMatch ? nameMatch[1].trim() : '',
    phone: phoneMatch ? phoneMatch[1].trim() : '',
    address: addressMatch ? addressMatch[1].trim() : '',
    total: totalMatch ? totalMatch[1].trim() : ''
  };

  cleanedResponse = aiResponse.replace(/ORDER_CONFIRMED[\s\S]*?END_ORDER/g, '').trim();
}

// Check for CANCELLED
else if (aiResponse.includes('CANCELLED')) {
  intent = 'cancel';
  status = 'cancelled';
  const reasonMatch = aiResponse.match(/Reason: ([^|]+)/);
  orderData = { reason: reasonMatch ? reasonMatch[1].trim() : 'User cancelled' };
  cleanedResponse = aiResponse.replace(/CANCELLED[\s\S]*?END_CANCELLED/g, '').trim();
}

// Check for NEGOTIATION
else if (aiResponse.includes('NEGOTIATION')) {
  intent = 'negotiation';
  status = 'negotiating';
  const offerMatch = aiResponse.match(/Offer: ([^|]+)/);
  const priceMatch = aiResponse.match(/NewPrice: \$?([^|]+)/);
  orderData = {
    discount: offerMatch ? offerMatch[1].trim() : '',
    newPrice: priceMatch ? priceMatch[1].trim() : ''
  };
  cleanedResponse = aiResponse.replace(/NEGOTIATION[\s\S]*?END_NEGOTIATION/g, '').trim();
}

// Check for booking intent
else if (aiResponse.toLowerCase().includes('book') || aiResponse.toLowerCase().includes('appointment')) {
  intent = 'booking';
}

// Clean the response (remove markdown, extra spaces)
cleanedResponse = cleanedResponse
  .replace(/[*_#`]/g, '')
  .replace(/\s+/g, ' ')
  .replace(/\|/g, ',')
  .trim();

// If cleanedResponse is empty after removing tags, use a default
if (!cleanedResponse) {
  cleanedResponse = aiResponse.replace(/ORDER_CONFIRMED|CANCELLED|NEGOTIATION|END_ORDER|END_CANCELLED|END_NEGOTIATION/g, '').trim();
}

return [{
  json: {
    ...$input.first().json,
    aiReply: aiResponse,
    cleanedReply: cleanedResponse,
    intent: intent,
    status: status,
    orderData: JSON.stringify(orderData),
    product: orderData.product || '',
    quantity: orderData.quantity || '',
    customerName: orderData.name || '',
    phone: orderData.phone || '',
    address: orderData.address || ''
  }
}];

// Handle order confirmation branch
const input = $input.first().json;

// You could add additional logic here like sending confirmation emails
console.log('Order confirmed:', input.orderData);

return [{
  json: {
    ...input,
    branch: 'order_confirmed',
    processedAt: new Date().toISOString()
  }
}];

// Handle negotiation branch
const input = $input.first().json;

// Track negotiation count (you would store this in a real session)
console.log('Negotiation in progress:', input.orderData);

return [{
  json: {
    ...input,
    branch: 'negotiation',
    processedAt: new Date().toISOString()
  }
}];

// Handle cancellation branch
const input = $input.first().json;

// Clear any stored order data
console.log('Order cancelled:', input.orderData);

return [{
  json: {
    ...input,
    branch: 'cancelled',
    processedAt: new Date().toISOString()
  }
}];

// Merge all branches back together
const input = $input.first().json;

return [{
  json: input
}];

// Prepare final webhook response
const input = $input.first().json;

// Create clean JSON response
const response = {
  reply: input.cleanedReply || input.aiReply || 'No response generated',
  intent: input.intent || 'general',
  status: input.status || 'completed',
  sessionId: input.sessionId,
  timestamp: new Date().toISOString()
};

// Add order data if present
if (input.orderData && input.orderData !== '{}') {
  try {
    response.orderDetails = JSON.parse(input.orderData);
  } catch (e) {
    response.orderDetails = input.orderData;
  }
}

return [{
  json: response
}];
